53	const PROCESSING_FEE = 5;
54	
55	const ITEM_BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const basePremiumFor = (item: Item): number => ITEM_BASE_PREMIUM[item.type];
64	
65	const COMPONENT_BLOCK_PREMIUM = 60;
66	
67	const sumBasePremiums = (items: Item[]): number =>
68	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
69	
70	const itemsBaseTotal = (items: Item[]): number => {
71	  const runeCount = items.filter((i) => i.type === "rune").length;
72	  if (runeCount === 3) {
73	    const nonRunes = items.filter((i) => i.type !== "rune");
74	    return COMPONENT_BLOCK_PREMIUM + sumBasePremiums(nonRunes);
75	  }
76	  return sumBasePremiums(items);
77	};
78	
79	const quote = ({ items }: QuoteStep): QuoteResult => ({
80	  premium: itemsBaseTotal(items) + PROCESSING_FEE,
81	});
82	
83	export const runScenario = (scenario: Scenario): ScenarioResult => ({
84	  results: scenario.steps.map((step) =>
85	    step.op === "quote" ? quote(step) : { payout: 0, remainingCap: 0 },
86	  ),
87	});
