const isRune = (item: Item): boolean => item.type === "rune";

const itemsBaseTotal = (items: Item[]): number => {
  const runes = items.filter(isRune);
  if (runes.length === 3) {
    const nonRunes = items.filter((i) => !isRune(i));
    return COMPONENT_BLOCK_PREMIUM + sumBasePremiums(nonRunes);
  }
  return sumBasePremiums(items);
};
